const now = new Date();
const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1);
const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 2, 0).getDate();
const month = nextMonth.getMonth();
const monthName = nextMonth.toLocaleString('en-US', { month: 'long' });

let season = 'spring';
if (month >= 5 && month <= 7) season = 'summer';
else if (month >= 8 && month <= 10) season = 'fall';
else if (month >= 11 || month <= 1) season = 'winter';

const contentMix = ['before_after','tip','testimonial','seasonal_promo','team_behindscenes'];
const contentWeights = [0.30, 0.20, 0.20, 0.20, 0.10];

const services = [
  'lawn_mowing','aeration','overseeding','fertilization','weed_control',
  'leaf_removal','spring_cleanup','fall_cleanup','gutter_cleaning',
  'snow_removal','hedge_trimming','mulching','edging','dethatching','irrigation'
];

const seasonalHashtags = {
  spring: '#SpringLawn #SpringCleanup #MadisonWI #TotalGuard',
  summer: '#SummerLawn #LawnCare #MadisonWI #TotalGuard',
  fall: '#FallCleanup #LeafRemoval #MadisonWI #TotalGuard',
  winter: '#SnowRemoval #WinterLawn #MadisonWI #TotalGuard'
};

const posts = [];
for (let day = 1; day <= daysInMonth; day++) {
  const postDate = new Date(nextMonth.getFullYear(), nextMonth.getMonth(), day, 10, 0, 0);
  const typeIndex = Math.floor(day / daysInMonth * contentMix.length * 3) % contentMix.length;
  const contentType = contentMix[typeIndex];
  const service = services[(day - 1) % services.length];
  const hashtags = seasonalHashtags[season];
  const caption = `${monthName} ${contentType.replace(/_/g,' ')} — ${service.replace(/_/g,' ')} by TotalGuard Yard Care. Serving Madison, Middleton, Waunakee & surrounding areas. Book at tgyardcare.com ${hashtags}`;
  posts.push({
    json: {
      content_type: contentType,
      service_type: service,
      season,
      caption,
      status: 'draft',
      scheduled_for: postDate.toISOString(),
      created_at: now.toISOString()
    }
  });
}
return posts;
